const root = items[0].json;
const query = root.query || {};
const body = root.body || {};
const submissionId = String(query.submissionId ?? body.submissionId ?? 'latest').trim() || 'latest';
items[0].json = { submissionId };
return items;

const row = items[0].json;
const rawBlob = String(row.raw_blob ?? row.rawBlob ?? '');
const pick = (label) => {
  const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const match = rawBlob.match(new RegExp(`${escaped}=([^|]+)`, 'i'));
  return match ? match[1].trim() : '';
};
const parsed = {
  submissionId: row.id ?? '',
  company: row.company ?? 'Kjells Konserverade Koi',
  createdAt: row.created_at ?? row.createdAt ?? '',
  rawBlob,
  name: pick('namn'),
  email: pick('email'),
  phone: pick('telefon'),
  product: pick('produkt'),
  quantity: pick('antal'),
  city: pick('stad'),
  channel: pick('kanal'),
  issue: pick('kommentar'),
  profileUrl: pick('profileUrl'),
};

const combined = `${parsed.product} ${parsed.issue} ${parsed.channel}`.toLowerCase();
parsed.category = /partner|event|pr/.test(combined)
  ? 'partnership'
  : /dubbla|skadad|problem|fel|avslappnad|paradox/.test(combined)
    ? 'support_case'
    : /offert|hotell|premium|antal|present|lobby|kampanj/.test(combined)
      ? 'bulk_order'
      : 'general_inquiry';

const esc = (value) => String(value ?? '')
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\"/g, '&quot;');

const rows = [
  ['Submission ID', parsed.submissionId],
  ['Företag', parsed.company],
  ['Skapad', parsed.createdAt],
  ['Namn', parsed.name],
  ['E-post', parsed.email],
  ['Telefon', parsed.phone],
  ['Produkt', parsed.product],
  ['Antal', parsed.quantity],
  ['Stad', parsed.city],
  ['Kanal', parsed.channel],
  ['Kategori', parsed.category],
  ['Kommentar', parsed.issue],
].filter(([, value]) => value);

const tableRows = rows.map(([label, value]) => `<tr><th>${esc(label)}</th><td>${esc(value)}</td></tr>`).join('');
const imageBlock = parsed.profileUrl
  ? `<div class=\"reward-card\"><img src=\"${esc(parsed.profileUrl)}\" alt=\"Reward image\" /><div><h2>Regex lyckades</h2><p>Fälten är nu extraherade ur en enda blob. Nästa steg kan vara CRM, spreadsheet eller supportyta.</p></div></div>`
  : `<div class=\"reward-card reward-empty\"><div><h2>Ingen profileUrl hittades</h2><p>Workflowet fungerade, men reward-bilden saknas eftersom blobben inte innehöll någon bild-URL.</p></div></div>`;
const rawBlock = `<details><summary>Visa ursprunglig blob</summary><pre>${esc(parsed.rawBlob)}</pre></details>`;
const rewardExample = esc(`curl -sS -X POST http://localhost:5678/webhook/legacy-reward-preview -H \"Content-Type: application/json\" -d '${JSON.stringify({
  submissionId: parsed.submissionId,
  company: parsed.company,
  name: parsed.name,
  email: parsed.email,
  phone: parsed.phone,
  product: parsed.product,
  quantity: parsed.quantity,
  city: parsed.city,
  category: parsed.category,
  issue: parsed.issue,
  source: 'n8n-legacy-regex-solution',
  profileUrl: parsed.profileUrl,
  rawBlob: parsed.rawBlob,
}).replace(/'/g, "'\\''")}'`);

parsed.html = `<!doctype html>
