    </style>
  </head>
  <body>
    <main>
      <section class=\"hero\">
        <span class=\"pill\">End-to-end solution</span>
        <h1>Legacy SQLite -> regex -> struktur -> preview</h1>
        <p>Detta workflow visar hela kedjan: hämta en blob från SQLite-vägen, regex-parsa ut riktiga fält och visa resultatet direkt som HTML i webbläsaren.</p>
      </section>
      <section class=\"grid\">
        <article class=\"panel\">
          <h2>Uppstrukturerade fält</h2>
          <table>${tableRows}</table>
          ${rawBlock}
        </article>
        <aside class=\"panel\">
          ${imageBlock}
          <p class=\"tiny\">Vill du i stället posta strukturerad JSON till en separat final webhook? Använd <code>/webhook/legacy-reward-preview</code>.</p>
          <pre>${rewardExample}</pre>
        </aside>
      </section>
    </main>
  </body>
</html>`;

items[0].json = parsed;
return items;
